import { Student, GlobalConfig, InvoiceDetail, Attendance } from '../types';

export const calculateAgeInMonths = (dob: string): number => {
  const birth = new Date(dob);
  const now = new Date();
  return (now.getFullYear() - birth.getFullYear()) * 12 + (now.getMonth() - birth.getMonth());
};

export const formatCurrency = (amount: number): string => {
  return new Intl.NumberFormat('vi-VN').format(amount);
};

export const calculateMonthsRemaining = (month: number): number => {
  return ((8 - month) % 12 + 12) % 12 + 1;
};

export const calculateInvoice = (
  student: Student,
  config: GlobalConfig,
  attendanceData: Attendance[],
  currentMonth: number,
  currentYear: number
): InvoiceDetail => {
  const ageMonths = calculateAgeInMonths(student.dob);
  const monthsRemaining = calculateMonthsRemaining(currentMonth);

  const currentAttendance = attendanceData.find(
    a => a.studentId === student.id && a.month === currentMonth && a.year === currentYear
  );

  const isFull = !!currentAttendance?.isFullDiscount;
  const isHalf = !!currentAttendance?.isHalfDiscount;

  // 1. Lấy giá gốc dựa trên tuổi
  let baseTuition = ageMonths >= 36 ? config.tuitionOver36 : config.tuitionUnder36;
  let finalTuition = baseTuition;

  // 2. Ưu tiên kiểm tra ô Giảm 100% trước
  let discountType: 'none' | '50%' | '100%' = 'none';
  if (isFull) {
    finalTuition = 0;
    discountType = '100%';
  } else if (isHalf) {
    finalTuition = baseTuition / 2;
    discountType = '50%';
  }

  // Tiền ăn tính theo tháng trước
  const lastMonth = currentMonth === 1 ? 12 : currentMonth - 1;
  const lastYear = currentMonth === 1 ? currentYear - 1 : currentYear;
  const lastMonthAttendance = attendanceData.find(
    a => a.studentId === student.id && a.month === lastMonth && a.year === lastYear
  );
  const absentDays = lastMonthAttendance ? lastMonthAttendance.absentDays : 0;
  const mealFee = (config.standardDays * config.mealFeePerDay) - (absentDays * config.mealFeePerDay);

  let giftedTotal = 0;
  const giftedBreakdown: string[] = [];

  // LOGIC SỬA ĐỔI: Miễn phí toàn bộ môn năng khiếu nếu isFull (Giảm 100%)
  if (student.giftedSubjects.english) {
    const fee = isFull ? 0 : config.giftedFees.english;
    giftedTotal += fee;
    giftedBreakdown.push(`Học Anh Văn : ${formatCurrency(fee)} đồng.${isFull ? ' (Miễn phí)' : ''}`);
  }
  if (student.giftedSubjects.drawing) {
    const fee = isFull ? 0 : config.giftedFees.drawing;
    giftedTotal += fee;
    giftedBreakdown.push(`Học Vẽ : ${formatCurrency(fee)} đồng.${isFull ? ' (Miễn phí)' : ''}`);
  }
  if (student.giftedSubjects.rhythm) {
    const fee = isFull ? 0 : config.giftedFees.rhythm;
    giftedTotal += fee;
    giftedBreakdown.push(`Học Nhịp Điệu : ${formatCurrency(fee)} đồng.${isFull ? ' (Miễn phí)' : ''}`);
  }

  let csvcFee = 0;
  let materialFee = 0;
  if (student.isNewStudent) {
    csvcFee = monthsRemaining * config.unitCSVC;
    const matUnitPrice = ageMonths >= 36 ? config.unitMaterialLon : config.unitMaterialNho;
    materialFee = monthsRemaining * matUnitPrice;
  }

  const total = finalTuition + mealFee + giftedTotal + csvcFee + materialFee + config.extraFee;

  return {
    student,
    tuition: finalTuition,
    mealFee,
    giftedTotal,
    csvcFee,
    materialFee,
    extraFee: config.extraFee,
    total,
    discountType,
    calculationInfo: {
      ageInMonths: ageMonths,
      absentDaysLastMonth: absentDays,
      monthsRemaining,
      giftedBreakdown
    }
  };
};

export const generateZaloMessage = (invoice: InvoiceDetail, month: number, year: number, config: GlobalConfig): string => {
  const { student, total, tuition, extraFee, csvcFee, materialFee, calculationInfo, discountType } = invoice;
  const formattedDOB = new Date(student.dob).toLocaleDateString('vi-VN');
  const fullMealFee = config.standardDays * config.mealFeePerDay;
  const absentDeduction = calculationInfo.absentDaysLastMonth * config.mealFeePerDay;

  let msg = `GIẤY BÁO ĐÓNG TIỀN HỌC PHÍ THÁNG ${month} NĂM ${year}.\n\n`;
  msg += `- Họ và tên trẻ : ${student.name.toUpperCase()} SN ${formattedDOB}-${calculationInfo.ageInMonths} tháng.\n`;

  let tuitionLabel = `Tiền học phí trong tháng`;
  if (discountType === '100%') tuitionLabel += ` (Miễn 100%)`;
  if (discountType === '50%') tuitionLabel += ` (Giảm 50% - Nửa tháng)`;

  msg += `- ${tuitionLabel} : ${formatCurrency(tuition)} đồng.\n`;
  msg += `- Tiền ăn trong tháng (${config.standardDays} ngày x ${formatCurrency(config.mealFeePerDay)}) : ${formatCurrency(fullMealFee)} đồng.\n`;

  calculationInfo.giftedBreakdown.forEach(item => {
    msg += `- ${item}\n`;
  });

  msg += `- Các khoản phụ thu (Vệ sinh phí, Gaz, Điện, Nước bình...) : ${formatCurrency(extraFee)} đồng.\n`;

  if (csvcFee > 0) msg += `- Cơ sở vật chất (${calculationInfo.monthsRemaining} tháng) : ${formatCurrency(csvcFee)} đồng.\n`;
  if (materialFee > 0) msg += `- Học phẩm (${calculationInfo.monthsRemaining} tháng) : ${formatCurrency(materialFee)} đồng.\n`;

  msg += `- Số ngày nghỉ có phép trong tháng : ${calculationInfo.absentDaysLastMonth} ngày . Trừ lại : ${formatCurrency(absentDeduction)} đồng.\n\n`;

  msg += `TỔNG CỘNG : ${formatCurrency(total)} đồng.\n\n`;
  msg += `Thông tin chuyển khoản: Tên thụ hưởng: TRẦN THỊ TRÚC GIANG\n`;
  msg += `Số tài khoản: 6350205 014046 Tại Ngân hàng Agribank Phước Kiển\n`;
  msg += `Nội dung chuyển khoản: ${student.name}, ${student.className}.\n\n`;
  msg += `Phụ huynh vui lòng đóng học phí từ ngày 1 đến 10 tây hàng tháng. Rất mong phụ huynh đóng học phí đúng thời gian qui định của nhà trường.\n`;
  msg += `Xin chân thành cảm ơn!`;

  return msg;
};

export interface GiftedSubjects {
  english: boolean;
  drawing: boolean;
  rhythm: boolean;
}

export interface Student {
  id: string;
  name: string;
  dob: string;
  className: string;
  giftedSubjects: GiftedSubjects;
  isNewStudent: boolean;
  admissionDate: string;
  phoneNumber?: string; 
}

export interface Attendance {
  studentId: string;
  month: number;
  year: number;
  absentDays: number;
  isHalfDiscount?: boolean; // Giảm 50%
  isFullDiscount?: boolean; // Giảm 100%
}

export interface GlobalConfig {
  tuitionOver36: number; 
  tuitionUnder36: number; 
  mealFeePerDay: number;
  extraFee: number;
  giftedFees: {
    english: number;
    drawing: number;
    rhythm: number;
  };
  unitCSVC: number;
  unitMaterialLon: number;
  unitMaterialNho: number;
  standardDays: number;
}

export interface InvoiceDetail {
  student: Student;
  tuition: number;
  mealFee: number;
  giftedTotal: number;
  csvcFee: number;
  materialFee: number;
  extraFee: number;
  total: number;
  discountType: 'none' | '50%' | '100%'; 
  calculationInfo: {
    ageInMonths: number;
    absentDaysLastMonth: number;
    monthsRemaining: number;
    giftedBreakdown: string[];
  };
}

import React, { useState, useRef } from 'react';
import { Plus, Search, Trash2, Edit2, X, Upload, Info, AlertCircle, FileSpreadsheet, FileUp, CheckCircle2, RefreshCw, Layers } from 'lucide-react';
import * as XLSX from 'xlsx';
import { Card, Badge } from './Common';
import { Student } from '../types';
import { calculateAgeInMonths } from '../utils/calculations';

interface StudentsProps {
  students: Student[];
  onAdd: (s: Student) => void;
  onUpdate: (s: Student) => void;
  onDelete: (id: string) => void;
  onImport: (list: Student[]) => void;
  onClearAll: () => void;
}

export const Students = ({ students, onAdd, onUpdate, onDelete, onImport, onClearAll }: StudentsProps) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeClassTab, setActiveClassTab] = useState<'all' | 'nursery' | 'preschool'>('all');
  const [showModal, setShowModal] = useState(false);
  const [editingStudent, setEditingStudent] = useState<Student | null>(null);
  const [isConfirmingClear, setIsConfirmingClear] = useState(false);
  const [importLoading, setImportLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Partial<Student>>({
    name: '',
    dob: '',
    className: 'Lớp Mầm 1',
    giftedSubjects: { english: false, drawing: false, rhythm: false },
    isNewStudent: false,
    admissionDate: new Date().toISOString().split('T')[0],
    phoneNumber: ''
  });

  const filteredStudents = students.filter(s => {
    const matchesSearch = s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         s.className.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         s.id.toLowerCase().includes(searchTerm.toLowerCase());

    const ageMonths = calculateAgeInMonths(s.dob);
    if (activeClassTab === 'nursery') return matchesSearch && ageMonths < 36;
    if (activeClassTab === 'preschool') return matchesSearch && ageMonths >= 36;
    return matchesSearch;
  });

  const handleOpenModal = (student?: Student) => {
    if (student) {
      setEditingStudent(student);
      setFormData(student);
    } else {
      setEditingStudent(null);
      setFormData({
        id: `HS${Date.now()}`,
        name: '',
        dob: '',
        className: 'Lớp Mầm 1',
        giftedSubjects: { english: false, drawing: false, rhythm: false },
        isNewStudent: false,
        admissionDate: new Date().toISOString().split('T')[0],
        phoneNumber: ''
      });
    }
    setShowModal(true);
  };

  const handleSave = () => {
    if (!formData.name || !formData.dob) {
      alert("Vui lòng nhập đầy đủ Tên và Ngày sinh!");
      return;
    }
    if (editingStudent) {
      onUpdate(formData as Student);
    } else {
      onAdd(formData as Student);
    }
    setShowModal(false);
  };

  const formatExcelDate = (value: any): string => {
    if (!value) return new Date().toISOString().split('T')[0];
    if (typeof value === 'number') {
      const date = new Date((value - 25569) * 86400 * 1000);
      return date.toISOString().split('T')[0];
    }
    const d = new Date(value);
    if (!isNaN(d.getTime())) return d.toISOString().split('T')[0];
    const parts = String(value).split(/[/-]/);
    if (parts.length === 3) {
      if (parts[2].length === 4) return `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
    }
    return String(value);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setImportLoading(true);
    const reader = new FileReader();

    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json: any[] = XLSX.utils.sheet_to_json(worksheet);

        const importedData: Student[] = json.map((row) => {
          const name = String(row['Họ và tên'] || row['Họ tên'] || row['Tên'] || row['Name'] || row['name'] || 'Không tên');
          const dob = formatExcelDate(row['Ngày sinh'] || row['NS'] || row['DOB'] || row['dob']);
          const className = String(row['Lớp'] || row['Lớp học'] || row['Class'] || row['class'] || 'Lớp Nhà trẻ');
          const phone = String(row['Số điện thoại'] || row['SĐT'] || row['Phone'] || row['PhoneNumber'] || '');
          const admission = formatExcelDate(row['Ngày nhập học'] || row['Ngày vào'] || row['AdmissionDate'] || new Date().toISOString().split('T')[0]);

          const statusRaw = String(row['Bé mới'] || row['Trạng thái'] || row['IsNewStudent'] || 'Cũ').toLowerCase();
          const isNew = statusRaw.includes('mới') || statusRaw === 'true';

          const rawId = row['ID'] || row['Mã số'];
          const generatedId = rawId ? String(rawId) : `HS-${name.replace(/\s+/g, '')}-${dob.replace(/-/g, '')}`;

          return {
            id: generatedId,
            name,
            dob,
            className,
            giftedSubjects: {
              english: String(row['Anh văn'] || row['English'] || '').toUpperCase() === 'TRUE',
              drawing: String(row['Vẽ'] || row['Drawing'] || '').toUpperCase() === 'TRUE',
              rhythm: String(row['Nhịp điệu'] || row['Rhythm'] || '').toUpperCase() === 'TRUE',
            },
            isNewStudent: isNew,
            admissionDate: admission,
            phoneNumber: phone
          };
        });

        if (importedData.length > 0) {
          onImport(importedData);
          alert(`Đã nạp gộp thành công ${importedData.length} bé vào danh sách!`);
        } else {
          alert('Không tìm thấy dữ liệu học sinh trong file!');
        }
      } catch (err) {
        alert('Lỗi khi đọc file Excel. Hãy kiểm tra các cột: Họ tên, Ngày sinh, Lớp...');
      } finally {
        setImportLoading(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };

    reader.readAsBinaryString(file);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-6">
        <div className="flex flex-col md:flex-row gap-4 flex-1">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Tìm tên bé, lớp hoặc ID..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all outline-none font-medium shadow-sm"
            />
          </div>

          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm">
            <button 
              onClick={() => setActiveClassTab('all')}
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeClassTab === 'all' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}
            >Tất cả ({students.length})</button>
            <button 
              onClick={() => setActiveClassTab('preschool')}
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeClassTab === 'preschool' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}
            >Khối Mẫu Giáo</button>
            <button 
              onClick={() => setActiveClassTab('nursery')}
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeClassTab === 'nursery' ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}
            >Khối Nhà Trẻ</button>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="relative">
            {isConfirmingClear ? (
              <div className="flex items-center gap-1 bg-red-600 rounded-2xl p-1 animate-in zoom-in duration-200">
                <button 
                  onClick={() => { onClearAll(); setIsConfirmingClear(false); }}
                  className="px-4 py-2 bg-white text-red-600 rounded-xl font-black text-[10px] uppercase shadow-lg"
                >BẤM ĐỂ XÓA HẾT!</button>
                <button 
                  onClick={() => setIsConfirmingClear(false)}
                  className="p-2 text-white hover:bg-red-700 rounded-xl"
